import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {}
for col, pol in policy.items():
    if pol == "required":
        n = int(df[col].isna().sum())
        if n > 0:
            viol[col] = n
print(viol)

import pandas as pd
df = pd.DataFrame({"cliente_id": ["C001"], "region": ["Lima"], "score": [1.0]})
sub = df[df.cliente_id == "C001"]
if len(sub) > 1 and sub.drop(columns=["cliente_id"]).duplicated(keep=False).any():
    print("exact")
elif sub["region"].nunique() > 1:
    print("conflict")
else:
    print("clean")
